final ThemeData themeDataDark = ThemeData( fontFamily: FontFamily.productSans, brightness: Brightness.dark, primaryColor: AppColors.teal[500], primaryColorBrightness: Brightness.dark, accentColor: AppColors.teal[500], accentColorBrightness: Brightness.dark, );

